# 输入获取
relations = [s.split("-") for s in input().split(",")]
breakdowns = input().split(",")


def remove(next, s):
    if next.get(s) is not None:
        need_remove = next[s]
        del next[s]

        for ss in need_remove:
            remove(next, ss)


# 算法入口
def getResult():
    next = {}
    first = {}

    i = 0
    for c, f in relations:
        if next.get(c) is None:
            next[c] = set()

        if next.get(f) is None:
            next[f] = set()

        next[f].add(c)

        if first.get(c) is None:
            first[c] = i
            i += 1

        if first.get(f) is None:
            first[f] = i
            i += 1

    for s in breakdowns:
        remove(next, s)

    ans = list(next.keys())
    if len(ans) == 0:
        return ","

    ans.sort(key=lambda x: first[x])

    return ",".join(ans)


# 算法调用
print(getResult())
